import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"梦幻马车","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/2.C级/梦幻马车.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/2.C级/梦幻马车.md"}'),d={name:"4.资源分区/7.物品与装备/7.载具及随从/载具/2.C级/梦幻马车.md"};function l(_,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"梦幻马车",tabindex:"-1"},[s("梦幻马车 "),e("a",{class:"header-anchor",href:"#梦幻马车","aria-label":'Permalink to "梦幻马车"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序007")])])],-1),o('<h1 id="梦幻马车-1" tabindex="-1">梦幻马车 <a class="header-anchor" href="#梦幻马车-1" aria-label="Permalink to &quot;梦幻马车&quot;">​</a></h1><p>梦幻马车<br> C+2500<br> 一辆被存放在魔法手环中的豪华古典马车，拥有四匹施加了飞行魔法的白马拖拽，该马车具备低空飞行能力，移动为良好，移动速度为60米/轮，防御面为20，体积9，结构值为35，梦幻马车会为它的乘客提供全遮蔽效果。<br> 当结构值降至四分之三时，视为损失一匹飞马，此后每降低四分之一便损失一匹飞马，当所有飞马都被击坠时，梦幻马车将无法再继续行动，如果在空中，则会不可遏制的坠落下去，但梦幻马车的设计者也考虑到了这一点，当梦幻马车坠落时，它将会缓慢自动下落，不会使乘客受到坠落伤害。<br> 马车内由于魔法原因具备比外表看起来更大的内部空间，总大小为10平米，高2米，具备2吨的承载能力，这视为一个储存空间。内部有奢华的装饰，拥有一个魔法壁炉、魔法餐桌和魔法留声机，魔法壁炉可以将马车内的温度永远保持舒适，而魔法餐桌则可以周期性的通过马车能量生成美味的魔法食物，魔法留声机则是可以播放多种乐曲，并且可以通过魔法手段将车内完全透视观察外部景观。<br> 备注：马车全速行驶下每小时能耗1点，每生产一次魔法美食能耗1点，每损失一匹飞马速度会降低四分之一。<br> 备注2：魔法马车无法依靠自身上升到水平面1000米以上的高度。<br> 表现力：通过手环唤醒马车，手环会在角色周围安全地带打开一个紫色传送门，马车会从该传送阵中跑出并停靠在角色身旁安全地带，马车的长度为4米宽3米高2米，拥有四个硕大的铁质车轮，车身为银白色华贵装饰并且带有魔法夜灯提供照明。马车内的正上方有一颗奥术水晶为整个马车提供魔法能源。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
